function siteSearch(){const q=(document.querySelector("#siteSearchInput")?.value||"world cup").toLowerCase();const box=document.querySelector("#searchResults");if(!box)return;const items=[["Latest Updates","news.html","Fresh football stories and tournament updates"],["Golden Boot","golden-boot.html","Top scorer race and player watchlist"],["Players","players.html","Player strengths and weaknesses"],["Teams","teams.html","Team power ranking and tactical notes"],["Predictions","predictions.html","Favorites and dark horses"],["World Cup Guide","world-cup-2026.html","Tournament format, dates and host guide"]];box.innerHTML=items.filter(x=>(x[0]+x[2]).toLowerCase().includes(q)||q.length<2||q.includes('world')||q.includes('cup')).map(x=>`<a class="card" href="${x[1]}"><span class="badge">Result</span><h3>${x[0]}</h3><p>${x[2]}</p></a>`).join("") || '<article class="card"><h3>No result found</h3><p>Try: team, player, Golden Boot, predictions or World Cup.</p></article>'}
function sharePage(text){const url=location.href;if(navigator.share)navigator.share({title:text,text,url});else if(navigator.clipboard){navigator.clipboard.writeText(url);alert("Link copied")}}
function esc(s){return String(s||"").replace(/[&<>\"']/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#039;"}[m]))}function attr(s){return String(s||"").replace(/['"]/g,"")}


// Mobile menu reliability and button click helpers
(function(){
  document.addEventListener('click', function(e){
    const menu=document.querySelector('.menu');
    const hamb=document.querySelector('.hamb');
    if(!menu||!hamb) return;
    if(e.target.closest('.hamb')){
      menu.classList.toggle('open');
      hamb.setAttribute('aria-expanded', menu.classList.contains('open') ? 'true':'false');
      e.stopPropagation();
      return;
    }
    if(e.target.closest('.menu a')){
      menu.classList.remove('open');
      hamb.setAttribute('aria-expanded','false');
      return;
    }
    if(menu.classList.contains('open') && !e.target.closest('.menu')){
      menu.classList.remove('open');
      hamb.setAttribute('aria-expanded','false');
    }
  }, true);
})();

function filterTeamCards(q){
  q=String(q||'').toLowerCase();
  document.querySelectorAll('#teamGrid .team-card').forEach(card=>{
    card.style.display=card.innerText.toLowerCase().includes(q)?'':'none';
  });
}

// First click opens the ad; after the visitor comes back, the same item works normally.
(function(){
  const smartlinkUrl='https://tolerateshyrenamed.com/wcdubmv7p?key=d154ac7cd6987b85b5ce83c8c8685e75';
  const memoryPrefix='ifu_smartlink_seen:';
  function targetKey(el){
    const href=el.getAttribute('href')||'';
    const onclick=el.getAttribute('onclick')||'';
    const text=(el.textContent||el.getAttribute('aria-label')||el.id||el.className||'click').trim().replace(/\s+/g,' ').slice(0,90);
    return memoryPrefix+location.pathname+'|'+el.tagName+'|'+href+'|'+onclick+'|'+text;
  }
  function shouldSkip(el){
    if(!el) return true;
    if(el.closest('[data-sponsored-ad], .ad-direct, input, textarea, select, label')) return true;
    const href=el.getAttribute('href')||'';
    if(href.startsWith('mailto:')||href.startsWith('tel:')||href.startsWith('javascript:')) return true;
    return false;
  }
  document.addEventListener('click',function(e){
    if(e.defaultPrevented||e.button!==0||e.metaKey||e.ctrlKey||e.shiftKey||e.altKey) return;
    const el=e.target.closest('a,button,[role="button"],summary');
    if(shouldSkip(el)) return;
    const key=targetKey(el);
    try{
      if(localStorage.getItem(key)) return;
      localStorage.setItem(key,'1');
    }catch(err){
      if(el.dataset.smartlinkSeen) return;
      el.dataset.smartlinkSeen='1';
    }
    e.preventDefault();
    e.stopPropagation();
    window.location.href=smartlinkUrl;
  },true);
})();
